/**
 * Drizzle Database Client
 * Singleton instance for database operations
 */

import { drizzle } from 'drizzle-orm/node-postgres';
import { Pool } from 'pg';

import * as schema from './schema.js';
import * as contentSchema from '../content/schema.js';
import * as pipelinesSchema from '../pipelines/schema.js';

// Create PostgreSQL connection pool
const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  max: 10,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

// Create Drizzle client with public, content, and pipelines schemas
export const db = drizzle(pool, { schema: { ...schema, ...contentSchema, ...pipelinesSchema } });

// Export schemas for convenience
export * from './schema.js';
export * from '../content/schema.js';
export * from '../pipelines/schema.js';

// Helper to close pool on shutdown
export async function closeDb() {
  await pool.end();
}

/**
 * Content Infrastructure — Drizzle ORM Schema
 *
 * All tables live in the PostgreSQL `content` schema, separate from
 * the existing `public` schema tables. Uses pgSchema('content').
 *
 * Authoritative reference: kitty-specs/006-content-infrastructure/data-model.md
 */

import { createId } from '@paralleldrive/cuid2';
import { relations } from 'drizzle-orm';
import {
  pgSchema,
  text,
  timestamp,
  boolean,
  integer,
  real,
  jsonb,
  uniqueIndex,
  index,
  primaryKey,
  customType,
} from 'drizzle-orm/pg-core';

// ============================================================
// SCHEMA NAMESPACE
// ============================================================

export const contentSchema = pgSchema('content');

// ============================================================
// CUSTOM TYPES
// ============================================================

/**
 * PostgreSQL tsvector type for full-text search.
 * The actual generated column + GIN index are handled via migration SQL.
 */
const tsvector = customType<{ data: string }>({
  dataType() {
    return 'tsvector';
  },
});

// ============================================================
// ENUMS
// ============================================================

export const sourceTypeEnum = contentSchema.enum('content_source_type', [

