      }

      // ------------------------------------------------------------------
      // Summary
      // ------------------------------------------------------------------

      return {
        status: 'completed' as const,
        executionId,
        tenantId,
        pipelineId,
        steps: {
          sourceQuery: {
            success: step1Result.success,
            isNoOp: step1Result.isNoOp ?? false,
